// ── WireLab Security Panel ────────────────────────────────────────────
// A full six-state alarm system living entirely in one script. This is the
// "everything" demo: it drives the on-board RGB LED, an ST7735 LCD over SPI,
// a PWM siren, an ADC tamper sensor, PIR + reed zones (raw pin edges), an
// RDM6300 keycard reader + remote text commands over UART1, and an I2C
// ambient sensor — coordinated by a state machine on `this`.
//
// States:  disarmed → arming → armed → entry → alarm → (lockout) → disarmed
// Attach point: the keypad button. Zones/UART/I2C broadcast to every script,
// so this one brain sees them all.

// ---- pure helpers (no `this`; they take what they need as arguments) ----

fn big_label(s) {
    if s == "disarmed" { "DISARMED" }
    else if s == "arming" { "ARMING" }
    else if s == "armed" { "ARMED" }
    else if s == "entry" { "ENTER CODE" }
    else if s == "alarm" { "!! ALARM !!" }
    else { "LOCKED OUT" }
}

fn state_bg(s) {
    if s == "disarmed" { [0, 40, 0] }
    else if s == "arming" { [55, 40, 0] }
    else if s == "armed" { [0, 0, 55] }
    else if s == "entry" { [65, 30, 0] }
    else if s == "alarm" { [95, 0, 0] }
    else { [35, 0, 0] }
}

// Triangle wave 0..80 with the given period, for smooth LED pulsing.
fn pulse(t, period) {
    let x = t % period;
    let half = period / 2;
    if x < half { x * 80 / half } else { (period - x) * 80 / half }
}

// Map the current state to an on-board RGB animation.
fn status_led(s, t) {
    if s == "disarmed" { rgb(0, 55, 0); }
    else if s == "arming" { let p = pulse(t, 500); rgb(p * 3 / 2, p, 0); }
    else if s == "armed" { let p = pulse(t, 1800); rgb(0, 0, p + 6); }
    else if s == "entry" { let p = pulse(t, 240); rgb(p * 3 / 2, p / 2, 0); }
    else if s == "alarm" { if (t / 110) % 2 == 0 { rgb(200, 0, 0); } else { rgb(0, 0, 0); } }
    else { rgb(30, 0, 0); }
}

// Wailing siren on GPIO25: sweep 600→1600 Hz each second, or silence.
fn siren(on, t) {
    if on { pin(25).pwm(600 + (t % 1000), 500); } else { pin(25).low(); }
}

// A short confirmation (ok) or reject (err) beep that auto-silences via after().
fn confirm(kind) {
    if kind == "ok" { pin(25).pwm(2200, 500); after(90, || pin(25).low()); }
    else { pin(25).pwm(320, 500); after(260, || pin(25).low()); }
}

// Repaint the whole panel: title bar, big state, sub-line, temp + light.
fn paint(s, sub, temp_c, light) {
    let bg = state_bg(s);
    lcd_clear(bg[0], bg[1], bg[2]);
    lcd_rect(0, 0, 128, 15, 18, 18, 28);
    lcd_text(6, 3, "WIRELAB SECURITY", 200, 205, 225);
    lcd_text(6, 34, big_label(s), 255, 255, 255);
    lcd_text(6, 58, sub, 215, 215, 220);
    lcd_text(6, 96, `TEMP ${temp_c}C`, 150, 220, 255);
    lcd_text(6, 112, `LIGHT ${light}`, 255, 220, 140);
}

// ---- lifecycle ----

fn on_start() {
    this.state = "disarmed";
    this.deadline = 0;      // millis() at which a timed state expires (0 = none)
    this.digits = 0;        // disarm-code digits entered
    this.fails = 0;         // failed disarm cycles (3 → lockout)
    this.temp_c = 0;        // last I2C ambient reading
    this.light_base = 0;    // tamper baseline captured while armed
    this.last_lcd = 0;
    this.last_i2c = 0;
    this.evt = "ready";     // sub-line shown on the LCD
    this.press_at = 0;      // for short/long press detection
    this.card = "0000ABCD"; // authorized keycard id

    lcd_init(6, 7, 8, 9, 23);   // ST7735 on SPI2: sck, mosi, cs, dc, rst
    uart(26, 24, 9600);         // RDM6300 keycard reader → RX 24
    i2c_setup(0, 1, 100);       // ambient sensor bus (SDA 0, SCL 1)
    pin(3).watch_analog(200);   // tamper LDR on ADC
    pin(25).low();              // siren off
    rgb(0, 55, 0);

    log(`WireLab security panel online on ${chip()}`);
    if board_has("wifi") { log("Wi-Fi present — remote arm/disarm over the link"); }
    paint("disarmed", "ready", 0, 0);
}

// ---- inputs ----

fn on_press() {
    this.press_at = millis();
}

fn on_release() {
    let held = millis() - this.press_at;

    // A long hold is a panic button from any state.
    if held > 1000 {
        this.state = "alarm";
        this.deadline = millis() + 20000;
        this.evt = "PANIC";
        confirm("err");
        log("PANIC");
        return;
    }

    let s = this.state;
    if s == "disarmed" {
        this.state = "arming";
        this.deadline = millis() + 15000;   // 15 s exit delay
        this.evt = "leave now";
        confirm("ok");
        log("arming");
    } else if s == "arming" {
        this.state = "disarmed";
        this.deadline = 0;
        this.evt = "cancelled";
        confirm("ok");
        log("disarmed");
    } else if s == "entry" || s == "alarm" {
        // Punch in the disarm code: four quick presses.
        this.digits = this.digits + 1;
        this.evt = `code ${this.digits}/4`;
        confirm("ok");
        if this.digits >= 4 {
            this.state = "disarmed";
            this.deadline = 0;
            this.digits = 0;
            this.fails = 0;
            this.evt = "welcome home";
            log("disarmed by code");
        }
    }
}

// Raw pin edges from the zones (PIR on GPIO5, reed door on GPIO10).
fn on_pin(gpio, high) {
    if !high || this.state != "armed" { return; }
    if gpio == 5 {
        this.state = "entry";               // motion: grace period to disarm
        this.deadline = millis() + 10000;
        this.digits = 0;
        this.evt = "motion zone 1";
        log("entry delay");
    } else if gpio == 10 {
        this.state = "alarm";               // door forced: instant
        this.deadline = millis() + 20000;
        this.evt = "DOOR forced";
        log("alarm: door");
    }
}

// UART1 carries both keycard ids (from the RDM6300) and remote text commands.
fn on_uart(line) {
    if line == this.card {
        if this.state != "disarmed" {
            this.state = "disarmed";
            this.deadline = 0;
            this.digits = 0;
            this.fails = 0;
            this.evt = "card accepted";
            confirm("ok");
            log("disarmed by keycard");
        }
    } else if line == "arm" && this.state == "disarmed" {
        this.state = "arming";
        this.deadline = millis() + 15000;
        this.evt = "remote arm";
        confirm("ok");
        log("remote arm");
    } else if line == "disarm" {
        this.state = "disarmed";
        this.deadline = 0;
        this.digits = 0;
        this.fails = 0;
        this.evt = "remote disarm";
        confirm("ok");
        log("remote disarm");
    } else if line == "status" {
        uart_send(`STATE ${this.state} TEMP ${this.temp_c}\r\n`);
    } else if this.state == "entry" || this.state == "alarm" {
        this.evt = "bad card";
        confirm("err");
    }
}

// I2C ambient sensor reply (a BME280-style read triggered from on_tick).
fn on_i2c(addr, data) {
    if data.len() > 0 { this.temp_c = data[0]; }
}

// The clock: animations, sensor polling, timed transitions, LCD refresh.
fn on_tick(dt) {
    let now = millis();
    let s = this.state;

    status_led(s, now);
    siren(s == "alarm", now);

    // Poll the ambient sensor every 2 s; the reply lands in on_i2c.
    if now - this.last_i2c > 2000 {
        this.last_i2c = now;
        i2c_read(0x76, 0xE3, 2);
    }

    // Tamper: a big swing in the panel light sensor while armed = intrusion.
    if s == "armed" {
        let light = pin(3).millivolts();
        if this.light_base == 0 { this.light_base = light + 1; }
        let d = light - this.light_base + 1;
        if d < 0 { d = -d; }
        if d > 800 {
            this.state = "alarm";
            this.deadline = now + 20000;
            this.evt = "TAMPER";
            log("alarm: tamper");
        }
    } else {
        this.light_base = 0;
    }

    // Timed transitions.
    if this.deadline != 0 && now >= this.deadline {
        if s == "arming" {
            this.state = "armed";
            this.deadline = 0;
            this.light_base = 0;
            this.evt = "all zones set";
            log("armed");
        } else if s == "entry" {
            this.state = "alarm";
            this.deadline = now + 20000;
            this.evt = "no code";
            log("alarm: entry timeout");
        } else if s == "alarm" {
            this.fails = this.fails + 1;
            if this.fails >= 3 {
                this.state = "lockout";
                this.deadline = now + 30000;
                this.evt = "too many trips";
                log("lockout");
            } else {
                this.state = "armed";
                this.deadline = 0;
                this.evt = "re-armed";
                log("re-armed");
            }
        } else if s == "lockout" {
            this.state = "disarmed";
            this.deadline = 0;
            this.fails = 0;
            this.evt = "ready";
            log("lockout cleared");
        }
    }

    // Repaint ~2x/sec with a live countdown.
    if now - this.last_lcd > 500 {
        this.last_lcd = now;
        let sub = this.evt;
        if this.deadline != 0 {
            let secs = (this.deadline - now) / 1000;
            if secs < 0 { secs = 0; }
            sub = `${this.evt} ${secs}s`;
        }
        paint(this.state, sub, this.temp_c, pin(3).millivolts());
    }
}
